21	template<typename T>
22	BertINT8<T>::BertINT8(size_t           max_batch_size,
23	                      size_t           max_seq_len,
24	                      size_t           head_num,
25	                      size_t           size_per_head,
26	                      size_t           inter_size,
27	                      size_t           num_layer,
28	                      int              sm,
29	                      float            q_scaling,
30	                      int              int8_mode,
31	                      cudaStream_t     stream,
32	                      cublasMMWrapper* cublas_wrapper,
33	                      IAllocator*      allocator,
34	                      bool             is_free_buffer_after_forward,
35	                      AttentionType    attention_type,
36	                      bool             sparse):
37	    max_batch_size_(max_batch_size),
38	    max_seq_len_(max_seq_len),
39	    head_num_(head_num),
40	    size_per_head_(size_per_head),
41	    inter_size_(inter_size),
42	    hidden_units_(head_num_ * size_per_head),
43	    num_layer_(num_layer),
44	    sm_(sm),
45	    q_scaling_(q_scaling),
46	    int8_mode_(int8_mode),
47	    stream_(stream),
48	    cublas_wrapper_(cublas_wrapper),
49	    allocator_(allocator),
50	    is_free_buffer_after_forward_(is_free_buffer_after_forward),
51	    attention_type_(attention_type),
52	    sparse_(sparse)
53	{
54	    if (int8_mode_ != 1 && int8_mode_ != 2 && int8_mode_ != 3) {
55	        throw std::runtime_error(std::string("[FT][ERROR] int8_mode_ not support \n"));
56	    }
57	    if (sparse_ && int8_mode_ == 1) {
58	        throw std::runtime_error(std::string("[FT][ERROR] int8_mode 1 does not support sparsity \n"));
59	    }
60	    if (int8_mode_ == 1
61	        && (attention_type == AttentionType::UNFUSED_MHA || attention_type == AttentionType::UNFUSED_PADDED_MHA)
62	        && (max_seq_len_ % 32 != 0)) {
63	        throw std::runtime_error(std::string(
64	            "[FT][ERROR] max_seq_len_ should be a multiple of 32 when int8_mode == 1 && && (attention_type == AttentionType::UNFUSED_MHA || attention_type == AttentionType::UNFUSED_PADDED_MHA)\n"));
65	    }
66	    bert_layer_ = new BertLayerINT8<T>(max_batch_size_,
67	                                       max_seq_len_,
68	                                       head_num_,
69	                                       size_per_head_,
70	                                       head_num_ * size_per_head_ * 4,
71	                                       sm_,
72	                                       q_scaling_,
73	                                       int8_mode_,
74	                                       stream_,
75	                                       cublas_wrapper_,
76	                                       allocator_,
77	                                       is_free_buffer_after_forward_,
78	                                       attention_type_,
79	                                       sparse_);
80	}
