125	template<typename T>
126	void BertINT8<T>::allocateBuffer()
127	{
128	    if (is_allocate_buffer_ == false) {
129	        h_pinned_token_num_ptr_ = (size_t*)allocator_->reMalloc(h_pinned_token_num_ptr_, sizeof(size_t), true, true);
130	        padding_offset_ =
131	            (int*)allocator_->reMalloc(padding_offset_, sizeof(int) * max_batch_size_ * max_seq_len_, false);
132	        trt_mha_padding_offset_ =
133	            (int*)allocator_->reMalloc(trt_mha_padding_offset_, sizeof(int) * (2 * max_batch_size_ + 1), false);
134	
135	        attention_mask_ =
136	            (T*)allocator_->reMalloc(attention_mask_, sizeof(T) * max_batch_size_ * max_seq_len_ * max_seq_len_, false);
137	
138	        bert_in_buffer_ = (T*)allocator_->reMalloc(
139	            bert_in_buffer_, sizeof(T) * max_batch_size_ * max_seq_len_ * head_num_ * size_per_head_, false);
140	        bert_out_buffer_ = (T*)allocator_->reMalloc(
141	            bert_out_buffer_, sizeof(T) * max_batch_size_ * max_seq_len_ * head_num_ * size_per_head_, false);
142	        is_allocate_buffer_ = true;
143	    }
144	}
145	
146	template<typename T>
147	void BertINT8<T>::freeBuffer()
148	{
149	    if (is_allocate_buffer_ == true) {
150	        allocator_->free((void**)(&h_pinned_token_num_ptr_), true);
151	        allocator_->free((void**)(&padding_offset_));
152	        allocator_->free((void**)(&trt_mha_padding_offset_));
153	
154	        allocator_->free((void**)(&attention_mask_));
155	        allocator_->free((void**)(&bert_in_buffer_));
156	        allocator_->free((void**)(&bert_out_buffer_));
157	        is_allocate_buffer_ = false;
158	    }
159	}
