161	template<typename T>
162	void BertINT8<T>::forward(std::vector<Tensor>*                       output_tensors,
163	                          const std::vector<Tensor>*                 input_tensors,
164	                          const std::vector<BertLayerINT8Weight<T>>* bert_layer_weights)
165	{
166	    // input_tensors: [input_query (batch, seqlen, hidden), sequence_length (batch)]
167	    // output_tensors: [output (batch, seqlen, size_per_head*head_num)]
168	    const size_t request_batch_size = input_tensors->at(0).shape[0];
169	    const size_t request_seq_len    = input_tensors->at(0).shape[1];
170	    FT_CHECK(input_tensors->size() == 2);
171	    FT_CHECK(isValidBatchSize(request_batch_size));
172	    FT_CHECK(isValidSeqLen(request_seq_len));
173	    FT_CHECK(request_batch_size == input_tensors->at(1).shape[0]);
174	    FT_CHECK(input_tensors->at(0).shape.size() == 3);
175	    FT_CHECK(input_tensors->at(1).shape.size() == 1);
176	    allocateBuffer();
177	
178	    const int* sequence_lengths = input_tensors->at(1).getPtr<const int>();
179	
180	    size_t h_token_num;
181	    T*     bert_input_ptr;
182	    T*     bert_output_ptr;
183	
184	    Tensor* padding_offset_tensor_ptr;
185	    switch (attention_type_) {
186	        case AttentionType::UNFUSED_MHA: {
187	            invokeBuildEncoderAttentionMask(
188	                attention_mask_, sequence_lengths, request_batch_size, request_seq_len, stream_);
189	            sync_check_cuda_error();
190	            invokeGetPaddingOffset(h_pinned_token_num_ptr_,
191	                                   &h_token_num,
192	                                   padding_offset_,
193	                                   sequence_lengths,
194	                                   request_batch_size,
195	                                   request_seq_len,
196	                                   stream_);
197	
198	            invokeRemovePadding(bert_in_buffer_,
199	                                input_tensors->at(0).getPtr<const T>(),
200	                                padding_offset_,
201	                                h_token_num,
202	                                head_num_ * size_per_head_,
203	                                stream_);
204	            sync_check_cuda_error();
205	            bert_input_ptr  = bert_in_buffer_;
206	            bert_output_ptr = bert_out_buffer_;
207	
208	            padding_offset_tensor_ptr =
209	                new Tensor(MEMORY_GPU, TYPE_INT32, std::vector<size_t>{h_token_num}, padding_offset_);
210	            break;
211	        }
212	        case AttentionType::UNFUSED_PADDED_MHA: {
213	            invokeBuildEncoderAttentionMask(
214	                attention_mask_, sequence_lengths, request_batch_size, request_seq_len, stream_);
215	            sync_check_cuda_error();
216	            h_token_num               = request_batch_size * request_seq_len;
217	            bert_input_ptr            = input_tensors->at(0).getPtr<T>();
218	            bert_output_ptr           = output_tensors->at(0).getPtr<T>();
219	            padding_offset_tensor_ptr = new Tensor(MEMORY_GPU, TYPE_INT32, std::vector<size_t>{0}, nullptr);
220	            break;
221	        }
222	        case AttentionType::FUSED_MHA: {
223	            invokeGetPaddingOffset(h_pinned_token_num_ptr_,
224	                                   &h_token_num,
225	                                   padding_offset_,
226	                                   sequence_lengths,
227	                                   request_batch_size,
228	                                   request_seq_len,
229	                                   stream_);
230	
231	            invokeRemovePadding(bert_in_buffer_,
232	                                input_tensors->at(0).getPtr<const T>(),
233	                                padding_offset_,
234	                                h_token_num,
235	                                head_num_ * size_per_head_,
236	                                stream_);
237	            sync_check_cuda_error();
238	            bert_input_ptr  = bert_in_buffer_;
239	            bert_output_ptr = bert_out_buffer_;
240	
241	            invokeGetTrtPaddingOffset(trt_mha_padding_offset_, sequence_lengths, request_batch_size, stream_);
242	
243	            padding_offset_tensor_ptr = new Tensor(
244	                MEMORY_GPU, TYPE_INT32, std::vector<size_t>{request_batch_size + 1}, trt_mha_padding_offset_);
245	            break;
246	        }
247	        case AttentionType::FUSED_PADDED_MHA: {
248	            h_token_num = request_batch_size * request_seq_len;
249	            invokeGetTrtPaddingOffset(
250	                trt_mha_padding_offset_, sequence_lengths, request_batch_size, request_seq_len, stream_);
251	            padding_offset_tensor_ptr = new Tensor(
252	                MEMORY_GPU, TYPE_INT32, std::vector<size_t>{request_batch_size * 2 + 1}, trt_mha_padding_offset_);
253	            bert_input_ptr  = input_tensors->at(0).getPtr<T>();
254	            bert_output_ptr = output_tensors->at(0).getPtr<T>();
255	            break;
256	        }
257	        default: {
258	            throw std::runtime_error(std::string("[FT][ERROR] Invalid attention type \n"));
259	        }
260	    }
261	
262	    DataType            data_type          = getTensorType<T>();
263	    std::vector<Tensor> tmp_output_tensors = {
264	        Tensor{MEMORY_GPU, data_type, std::vector<size_t>{h_token_num, hidden_units_}, bert_output_ptr},
265	    };
266	
267	    int num_layer_ptr[1] = {int(num_layer_)};
268	    int layer_idx_ptr[1] = {-1};
269	    for (uint i = 0; i < num_layer_; i++) {
270	        layer_idx_ptr[0] = i;
271	        std::vector<Tensor> tmp_input_tensors{
272	            Tensor{MEMORY_GPU,
273	                   data_type,
274	                   std::vector<size_t>{h_token_num, hidden_units_},
275	                   i == 0 ? bert_input_ptr : bert_output_ptr},
276	            Tensor{MEMORY_GPU,
277	                   data_type,
278	                   std::vector<size_t>{request_batch_size, 1, request_seq_len, request_seq_len},
279	                   attention_mask_},
280	            *padding_offset_tensor_ptr,
281	            Tensor{MEMORY_CPU, TYPE_INT32, std::vector<size_t>{1}, layer_idx_ptr},
282	            Tensor{MEMORY_CPU, TYPE_INT32, std::vector<size_t>{1}, num_layer_ptr},
283	        };
284	        bert_layer_->forward(&tmp_output_tensors, &tmp_input_tensors, &bert_layer_weights->at(i));
285	    }
286	
287	    switch (attention_type_) {
288	        case AttentionType::UNFUSED_MHA: {
289	            invokeRebuildPadding(output_tensors->at(0).getPtr<T>(),
290	                                 bert_out_buffer_,
291	                                 padding_offset_,
292	                                 h_token_num,
293	                                 head_num_ * size_per_head_,
294	                                 stream_);
295	            break;
296	        }
297	        case AttentionType::UNFUSED_PADDED_MHA: {
298	            break;
299	        }
300	        case AttentionType::FUSED_MHA: {
301	            invokeRebuildPadding(output_tensors->at(0).getPtr<T>(),
302	                                 bert_out_buffer_,
303	                                 padding_offset_,
304	                                 h_token_num,
305	                                 head_num_ * size_per_head_,
306	                                 stream_);
307	            break;
308	        }
309	        case AttentionType::FUSED_PADDED_MHA: {
310	            break;
311	        }
312	        default: {
313	            throw std::runtime_error(std::string("[FT][ERROR] Invalid attention type \n"));
314	        }
315	    }
316	
317	    if (is_free_buffer_after_forward_ == true) {
318	        freeBuffer();
319	    }
320	    sync_check_cuda_error();
321	
322	    delete padding_offset_tensor_ptr;
323	}
324	
325	template<typename T>
326	bool BertINT8<T>::isValidBatchSize(size_t batch_size)
327	{
328	    if (max_batch_size_ == 0) {
329	        max_batch_size_ = batch_size;
330	        return true;
331	    }
332	    else {
333	        return batch_size <= max_batch_size_;
334	    }
335	}
336	
337	template<typename T>
338	bool BertINT8<T>::isValidSeqLen(size_t seq_len)
339	{
340	    if (max_seq_len_ == 0) {
341	        max_seq_len_ = seq_len;
342	        return true;
343	    }
344	    else {
345	        return seq_len <= max_seq_len_;
346	    }
347	}
348	
349	template class BertINT8<float>;
350	template class BertINT8<half>;
351	
352	}  // namespace fastertransformer
