162	// for layer_idx == 0, the data_type of input should be T, we need to quantize the input;
163	// for layer_idx == 0, the layout of input should be row-major, we need to transform the input;
164	// for layer_idx != 0, the data_type of input should be int8 for int8_mode=2/3, and T for int8_mode=1 (we need to
165	// quantize for int8_mode=1); for layer_idx != 0, the layout of input should be COL32.
166	
167	template<typename T>
168	void BertLayerINT8<T>::forward(std::vector<Tensor>*       output_tensors,
169	                               const std::vector<Tensor>* input_tensors,
170	                               const BertLayerWeight<T>*  bert_layer_weight)
171	{
172	    const BertLayerINT8Weight<T>* bert_layer_int8_weight = (const BertLayerINT8Weight<T>*)bert_layer_weight;
173	    const ScaleList*              scale_list             = &(bert_layer_int8_weight->scale_list_);
174	
175	    // input_tensors: [input_query (token_num, hidden_dimension),
176	    //                 attention_mask (batch, 1, seqlen, seqlen),
177	    //                 padding_offset (token_num),
178	    //                 layer_idx (1),
179	    //                 num_layer (1)]
180	    // output_tensors: [output (token_num, hidden_dimension)]
181	    // If padding_offset.data is nullptr, then not remove padding
182	
183	    FT_CHECK(input_tensors->size() == 5);
184	    FT_CHECK(input_tensors->at(0).shape.size() == 2);
185	    FT_CHECK(input_tensors->at(1).shape.size() == 4);
186	
187	    FT_CHECK(isValidBatchSize(input_tensors->at(1).shape[0]));
188	    FT_CHECK(isValidSeqLen(input_tensors->at(1).shape[2]));
189	    allocateBuffer();
190	
191	    T* from_tensor = input_tensors->at(0).getPtr<T>();
192	    T* out_tensor  = output_tensors->at(0).getPtr<T>();
193	
194	    const size_t m = input_tensors->at(0).shape[0];
195	    const size_t n = hidden_units_;
196	
197	    const int layer_idx = input_tensors->at(3).getVal<const int>();
198	    const int num_layer = input_tensors->at(4).getVal<const int>();
199	
200	    TensorMap attn_output_tensors{
201	        {"hidden_features", Tensor{MEMORY_GPU, getTensorType<int>(), std::vector<size_t>{m, n}, attn_out_buf_}},
202	    };
203	
204	    if (int8_mode_ == 1) {
205	
206	        if (layer_idx == 0) {
207	            invokeTransposeMatrixColMajorToCOL32(col32_from_tensor_, from_tensor, n, m, stream_);
208	            from_tensor = col32_from_tensor_;
209	        }
210	        invokeQuantization(int8_buf_, from_tensor, m * n, &(scale_list->d_scale_list_[3]), stream_);
211	        TensorMap int8_input_tensors{
212	            {"input_query", Tensor{MEMORY_GPU, TYPE_INT8, std::vector<size_t>{m, n}, int8_buf_}},
213	            {"attention_mask", input_tensors->at(1)},
214	            {"padding_offset", input_tensors->at(2)}};
215	        attention_layer_->forward(
216	            &attn_output_tensors, &int8_input_tensors, &bert_layer_int8_weight->attention_weights);
217	        // int32 I ; DataType O
218	
219	        PUSH_RANGE("post layernorm 1");
220	        invokeAddBiasResidualLayerNormCol32(layer_norm_tmp_buf_,
221	                                            attn_out_buf_,
222	                                            from_tensor,
223	                                            bert_layer_int8_weight->attention_weights.attention_output_weight.bias,
224	                                            bert_layer_int8_weight->attn_layernorm_weights.gamma,
225	                                            bert_layer_int8_weight->attn_layernorm_weights.beta,
226	                                            m,
227	                                            n,
228	                                            stream_,
229	                                            &(scale_list->d_scale_list_[scale_list->p2_offset_ + 3 * hidden_units_]),
230	                                            &(scale_list->d_scale_list_[36]));
231	        POP_RANGE;
232	        invokeQuantization(int8_buf_, layer_norm_tmp_buf_, m * n, &(scale_list->d_scale_list_[44 + 3]), stream_);
233	        std::vector<Tensor> ffn_input_tensors{Tensor{MEMORY_GPU, TYPE_INT8, std::vector<size_t>{m, n}, int8_buf_}};
234	        // reuse attn_output_tensors as ffn_output_tensors
235	        std::vector<Tensor> ffn_output_tensors{attn_output_tensors.at("hidden_features")};
236	        ffn_layer_->forward(&ffn_output_tensors, &ffn_input_tensors, &bert_layer_int8_weight->ffn_weights);
237	        PUSH_RANGE("post layernorm 2");
238	        if (layer_idx != num_layer - 1) {
239	            // int32 I ; DataType O
240	            invokeAddBiasResidualLayerNormCol32(
241	                out_tensor,
242	                attn_out_buf_,
243	                layer_norm_tmp_buf_,
244	                bert_layer_int8_weight->ffn_weights.output_weight.bias,
245	                bert_layer_int8_weight->ffn_layernorm_weights.gamma,
246	                bert_layer_int8_weight->ffn_layernorm_weights.beta,
247	                m,
248	                n,
249	                stream_,
250	                &(scale_list->d_scale_list_[scale_list->p2_offset_ + 8 * hidden_units_]),
251	                &(scale_list->d_scale_list_[52]));
252	        }
253	        else {
254	            // int32 I ; DataType O
255	            invokeAddBiasResidualLayerNormCol32(
256	                transformer_out_tmp_DataType_,
257	                attn_out_buf_,
258	                layer_norm_tmp_buf_,
259	                bert_layer_int8_weight->ffn_weights.output_weight.bias,
260	                bert_layer_int8_weight->ffn_layernorm_weights.gamma,
261	                bert_layer_int8_weight->ffn_layernorm_weights.beta,
262	                m,
263	                n,
264	                stream_,
265	                &(scale_list->d_scale_list_[scale_list->p2_offset_ + 8 * hidden_units_]),
266	                &(scale_list->d_scale_list_[52]));
267	
268	            invokeTransposeMatrixCOL32ToColMajor(out_tensor, transformer_out_tmp_DataType_, m, n, stream_);
269	        }
270	        POP_RANGE;
271	    }
272	    else if (int8_mode_ == 2 || int8_mode_ == 3) {
273	
274	        if (layer_idx == 0) {
275	#ifdef SPARSITY_ENABLED
276	            if (sparse_) {
277	                invokeQuantization(int8_buf_, from_tensor, m * n, &(scale_list->d_scale_list_[3]), stream_);
278	            }
279	            else {
280	#endif
281	                invokeTransposeMatrixColMajorToCOL32Quantize(
282	                    int8_buf_, from_tensor, n, m, &(scale_list->d_scale_list_[3]), stream_);
283	#ifdef SPARSITY_ENABLED
284	            }
285	#endif
286	            TensorMap int8_input_tensors{
287	                {"input_query", Tensor{MEMORY_GPU, TYPE_INT8, std::vector<size_t>{m, n}, int8_buf_}},
288	                {"attention_mask", input_tensors->at(1)},
289	                {"padding_offset", input_tensors->at(2)}};
290	            attention_layer_->forward(
291	                &attn_output_tensors, &int8_input_tensors, &bert_layer_int8_weight->attention_weights);
292	        }
293	        else {
294	            TensorMap attn_input_tensors{{"input_query", input_tensors->at(0)},
295	                                         {"attention_mask", input_tensors->at(1)},
296	                                         {"padding_offset", input_tensors->at(2)}};
297	            attention_layer_->forward(
298	                &attn_output_tensors, &attn_input_tensors, &bert_layer_int8_weight->attention_weights);
299	        }
300	        PUSH_RANGE("post layernorm 1");
301	        const int8_t* residual = layer_idx == 0 ? int8_buf_ : (const int8_t*)from_tensor;
302	        // int8 IO
303	#ifdef SPARSITY_ENABLED
304	        if (sparse_) {
305	            invokeAddBiasResidualLayerNormRow((int8_t*)layer_norm_tmp_buf_,
306	                                              (const int8_t*)attn_out_buf_,
307	                                              residual,
308	                                              bert_layer_int8_weight->attention_weights.attention_output_weight.bias,
309	                                              bert_layer_int8_weight->attn_layernorm_weights.gamma,
310	                                              bert_layer_int8_weight->attn_layernorm_weights.beta,
311	                                              m,
312	                                              n,
313	                                              stream_,
314	                                              &(scale_list->d_scale_list_[40 + 1]),
315	                                              &(scale_list->d_scale_list_[0 + 1]),
316	                                              &(scale_list->d_scale_list_[44 + 3]));
317	        }
318	        else {
319	#endif
320	            invokeAddBiasResidualLayerNormCol32((int8_t*)layer_norm_tmp_buf_,
321	                                                (const int8_t*)attn_out_buf_,
322	                                                residual,
323	                                                bert_layer_int8_weight->attention_weights.attention_output_weight.bias,
324	                                                bert_layer_int8_weight->attn_layernorm_weights.gamma,
325	                                                bert_layer_int8_weight->attn_layernorm_weights.beta,
326	                                                m,
327	                                                n,
328	                                                stream_,
329	                                                &(scale_list->d_scale_list_[40 + 1]),
330	                                                &(scale_list->d_scale_list_[0 + 1]),
331	                                                &(scale_list->d_scale_list_[44 + 3]));
332	#ifdef SPARSITY_ENABLED
333	        }
334	#endif
335	        POP_RANGE;
336	        std::vector<Tensor> ffn_input_tensors{
337	            Tensor{MEMORY_GPU, TYPE_INT8, std::vector<size_t>{m, n}, layer_norm_tmp_buf_}};
338	        // reuse attn_output_tensors as ffn_output_tensors
339	        std::vector<Tensor> ffn_output_tensors{attn_output_tensors.at("hidden_features")};
340	        ffn_layer_->forward(&ffn_output_tensors, &ffn_input_tensors, &bert_layer_int8_weight->ffn_weights);
341	        if (layer_idx != num_layer - 1) {
342	            // int8 IO
343	#ifdef SPARSITY_ENABLED
344	            if (sparse_) {
345	                PUSH_RANGE("post layernorm 2");
346	                invokeAddBiasResidualLayerNormRow((int8_t*)out_tensor,
347	                                                  (int8_t*)attn_out_buf_,
348	                                                  (int8_t*)layer_norm_tmp_buf_,
349	                                                  bert_layer_int8_weight->ffn_weights.output_weight.bias,
350	                                                  bert_layer_int8_weight->ffn_layernorm_weights.gamma,
351	                                                  bert_layer_int8_weight->ffn_layernorm_weights.beta,
352	                                                  m,
353	                                                  n,
354	                                                  stream_,
355	                                                  &(scale_list->d_scale_list_[56 + 1]),
356	                                                  &(scale_list->d_scale_list_[44 + 1]),
357	                                                  &(scale_list->d_scale_list_[60 + 3]));
358	                POP_RANGE;
359	            }
360	            else {
361	#endif
362	                PUSH_RANGE("post layernorm 2");
363	                invokeAddBiasResidualLayerNormCol32((int8_t*)out_tensor,
364	                                                    (int8_t*)attn_out_buf_,
365	                                                    (int8_t*)layer_norm_tmp_buf_,
366	                                                    bert_layer_int8_weight->ffn_weights.output_weight.bias,
367	                                                    bert_layer_int8_weight->ffn_layernorm_weights.gamma,
368	                                                    bert_layer_int8_weight->ffn_layernorm_weights.beta,
369	                                                    m,
