386	                                                  (int8_t*)layer_norm_tmp_buf_,
387	                                                  bert_layer_int8_weight->ffn_weights.output_weight.bias,
388	                                                  bert_layer_int8_weight->ffn_layernorm_weights.gamma,
389	                                                  bert_layer_int8_weight->ffn_layernorm_weights.beta,
390	                                                  m,
391	                                                  n,
392	                                                  stream_,
393	                                                  &(scale_list->d_scale_list_[56 + 1]),
394	                                                  &(scale_list->d_scale_list_[44 + 1]));
395	                POP_RANGE;
396	            }
397	            else {
398	#endif
399	                // int8 I ; DataType O
400	                PUSH_RANGE("post layernorm 2");
401	                invokeAddBiasResidualLayerNormCol32(transformer_out_tmp_DataType_,
402	                                                    (int8_t*)attn_out_buf_,
403	                                                    (int8_t*)layer_norm_tmp_buf_,
404	                                                    bert_layer_int8_weight->ffn_weights.output_weight.bias,
405	                                                    bert_layer_int8_weight->ffn_layernorm_weights.gamma,
406	                                                    bert_layer_int8_weight->ffn_layernorm_weights.beta,
407	                                                    m,
