410	                                                    &(scale_list->d_scale_list_[56 + 1]),
411	                                                    &(scale_list->d_scale_list_[44 + 1]));
412	
413	                invokeTransposeMatrixCOL32ToColMajor(out_tensor, transformer_out_tmp_DataType_, m, n, stream_);
414	                POP_RANGE;
415	#ifdef SPARSITY_ENABLED
416	            }
417	#endif
418	        }
419	    }
420	
421	    sync_check_cuda_error();
422	    if (is_free_buffer_after_forward_ == true) {
423	        freeBuffer();
424	    }
425	}
426	
427	template<typename T>
428	bool BertLayerINT8<T>::isValidBatchSize(size_t batch_size)
429	{
430	    if (max_batch_size_ == 0) {
431	        max_batch_size_ = batch_size;
432	        return true;
433	    }
434	    else {
435	        return batch_size <= max_batch_size_;
436	    }
437	}
