22	static inline __device__ int8_t float_to_int8_rn(float x)
23	{
24	    uint32_t dst;
25	    asm volatile("cvt.rni.sat.s8.f32 %0, %1;" : "=r"(dst) : "f"(x));
26	    return reinterpret_cast<const int8_t&>(dst);
