29	static inline __device__ uint32_t float4_to_char4(float x,
30	                                                  float y,
31	                                                  float z,
32	                                                  float w) {
33	  uint32_t dst;
34	#if defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 720
35	  uint32_t a; asm volatile("cvt.rni.sat.s32.f32 %0, %1;\n" : "=r"(a) : "f"(x));
36	  uint32_t b; asm volatile("cvt.rni.sat.s32.f32 %0, %1;\n" : "=r"(b) : "f"(y));
37	  uint32_t c; asm volatile("cvt.rni.sat.s32.f32 %0, %1;\n" : "=r"(c) : "f"(z));
38	  uint32_t d; asm volatile("cvt.rni.sat.s32.f32 %0, %1;\n" : "=r"(d) : "f"(w));
39	
40	  asm volatile("cvt.pack.sat.s8.s32.b32 %0, %1, %2,  0;\n" : "=r"(dst) : "r"(d), "r"(c));
41	  asm volatile("cvt.pack.sat.s8.s32.b32 %0, %1, %2, %0;\n" : "+r"(dst) : "r"(b), "r"(a));
42	#else
43	  char4 tmp;
44	  tmp.x = x;
45	  tmp.y = y;
46	  tmp.z = z;
47	  tmp.w = w;
48	  dst = reinterpret_cast<const uint32_t&>(tmp);
49	#endif
50	  return dst;
51	}

