84	void cublasINT8MMWrapper::Gemm(int*          res,
85	                               int           batchCount,
86	                               int           m,
87	                               int           n,
88	                               int           k,
89	                               int64_t       stridea,
90	                               int64_t       strideb,
91	                               int64_t       stridec,
92	                               const int8_t* ATransform,
93	                               const int8_t* kernel)
94	{
95	    mu_->lock();
96	    cublasOperation_t opTranspose = CUBLAS_OP_T;
97	#if (CUDART_VERSION >= 11000)
98	    cublasComputeType_t computeType = CUBLAS_COMPUTE_32I;
99	#else
100	    cudaDataType_t computeType = CUDA_R_32I;
101	#endif
102	    cublasLtMatmulDesc_t   matmulDesc;
103	    cublasLtMatrixLayout_t AtransformDesc = NULL;
104	    cublasLtMatrixLayout_t BtransformDesc = NULL;
105	    cublasLtMatrixLayout_t CtransformDesc = NULL;
106	    cublasLtOrder_t        order_COL32    = CUBLASLT_ORDER_COL32;
107	
108	    cublasLtOrder_t order_matrixB;
109	#if (CUDART_VERSION >= 11000)
110	    if (use_ORDER_COL32_2R_4R4_) {
111	        order_matrixB = CUBLASLT_ORDER_COL32_2R_4R4;
112	    }
113	    else {
114	        order_matrixB = CUBLASLT_ORDER_COL4_4R2_8C;
115	    }
116	#else
117	    order_matrixB              = CUBLASLT_ORDER_COL4_4R2_8C;
118	#endif
119	
120	    int ldaTransform = 32 * m;
121	    int ldbTransform;
122	    if (use_ORDER_COL32_2R_4R4_) {
123	        ldbTransform = 32 * ((n + 32 - 1) / 32) * 32;
124	    }
125	    else {
126	        ldbTransform = 32 * ((n + 8 - 1) / 8) * 8;
127	    }
128	    int ldcTransform = 32 * m;
129	
130	    // create matmulDesc
131	#if (CUDART_VERSION >= 11000)
132	    cublasLtMatmulDescCreate(&matmulDesc, computeType, CUDA_R_32I);
133	#else
134	    cublasLtMatmulDescCreate(&matmulDesc, computeType);
135	#endif
136	    cublasLtMatmulDescSetAttribute(matmulDesc, CUBLASLT_MATMUL_DESC_TRANSB, &opTranspose, sizeof(cublasOperation_t));
137	    cublasLtMatrixLayoutCreate(&AtransformDesc, CUDA_R_8I, m, k, ldaTransform);
138	    cublasLtMatrixLayoutSetAttribute(AtransformDesc, CUBLASLT_MATRIX_LAYOUT_ORDER, &order_COL32, sizeof(order_COL32));
139	    cublasLtMatrixLayoutCreate(&BtransformDesc, CUDA_R_8I, n, k, ldbTransform);
140	    cublasLtMatrixLayoutSetAttribute(
141	        BtransformDesc, CUBLASLT_MATRIX_LAYOUT_ORDER, &order_matrixB, sizeof(order_matrixB));
142	    cublasLtMatrixLayoutCreate(&CtransformDesc, CUDA_R_32I, m, n, ldcTransform);
143	    cublasLtMatrixLayoutSetAttribute(CtransformDesc, CUBLASLT_MATRIX_LAYOUT_ORDER, &order_COL32, sizeof(order_COL32));
144	    if (batchCount > 1) {
145	        cublasLtMatrixLayoutSetAttribute(
146	            AtransformDesc, CUBLASLT_MATRIX_LAYOUT_BATCH_COUNT, &batchCount, sizeof(batchCount));
147	        cublasLtMatrixLayoutSetAttribute(
148	            AtransformDesc, CUBLASLT_MATRIX_LAYOUT_STRIDED_BATCH_OFFSET, &stridea, sizeof(stridea));
149	        cublasLtMatrixLayoutSetAttribute(
150	            BtransformDesc, CUBLASLT_MATRIX_LAYOUT_BATCH_COUNT, &batchCount, sizeof(batchCount));
151	        cublasLtMatrixLayoutSetAttribute(
152	            BtransformDesc, CUBLASLT_MATRIX_LAYOUT_STRIDED_BATCH_OFFSET, &strideb, sizeof(strideb));
153	        cublasLtMatrixLayoutSetAttribute(
154	            CtransformDesc, CUBLASLT_MATRIX_LAYOUT_BATCH_COUNT, &batchCount, sizeof(batchCount));
155	        cublasLtMatrixLayoutSetAttribute(
156	            CtransformDesc, CUBLASLT_MATRIX_LAYOUT_STRIDED_BATCH_OFFSET, &stridec, sizeof(stridec));
157	    }
158	
159	    int alphaI = 1;
160	    int betaI  = 0;
161	
162	    // get algo
163	    cublasLtMatmulAlgo_t algo;
164	    int                  findAlgo = 0;
