170	
171	        cublasLtMatmulAlgoInit(cublaslt_handle_,
172	                               computeType,
173	                               CUDA_R_32I,
174	                               CUDA_R_8I,
175	                               CUDA_R_8I,
176	                               CUDA_R_32I,
177	                               CUDA_R_32I,
