179	                               &algo);
180	        cublasLtMatmulAlgoConfigSetAttribute(
181	            &algo, CUBLASLT_ALGO_CONFIG_CUSTOM_OPTION, &(tmp_info.customOption), sizeof(tmp_info.customOption));
182	        cublasLtMatmulAlgoConfigSetAttribute(
183	            &algo, CUBLASLT_ALGO_CONFIG_TILE_ID, &(tmp_info.tile), sizeof(tmp_info.tile));
184	        cublasLtMatmulAlgoConfigSetAttribute(
185	            &algo, CUBLASLT_ALGO_CONFIG_SPLITK_NUM, &(tmp_info.splitK_val), sizeof(tmp_info.splitK_val));
186	        cublasLtMatmulAlgoConfigSetAttribute(
187	            &algo, CUBLASLT_ALGO_CONFIG_CTA_SWIZZLING, &(tmp_info.swizzle), sizeof(tmp_info.swizzle));
188	        cublasLtMatmulAlgoConfigSetAttribute(
