206	        int tile            = 20;
207	        int splitK_val      = 0;
208	        int reductionScheme = 0;
209	        cublasLtMatmulAlgoInit(
210	            cublaslt_handle_, computeType, CUDA_R_32I, CUDA_R_8I, CUDA_R_8I, CUDA_R_32I, CUDA_R_32I, algoId, &algo);
211	        cublasLtMatmulAlgoConfigSetAttribute(
212	            &algo, CUBLASLT_ALGO_CONFIG_CUSTOM_OPTION, &(customOption), sizeof(customOption));
213	        cublasLtMatmulAlgoConfigSetAttribute(&algo, CUBLASLT_ALGO_CONFIG_TILE_ID, &(tile), sizeof(tile));
214	        cublasLtMatmulAlgoConfigSetAttribute(&algo, CUBLASLT_ALGO_CONFIG_SPLITK_NUM, &(splitK_val), sizeof(splitK_val));
215	        cublasLtMatmulAlgoConfigSetAttribute(&algo, CUBLASLT_ALGO_CONFIG_CTA_SWIZZLING, &(swizzle), sizeof(swizzle));
216	        cublasLtMatmulAlgoConfigSetAttribute(
217	            &algo, CUBLASLT_ALGO_CONFIG_REDUCTION_SCHEME, &(reductionScheme), sizeof(int));
218	#if (CUDART_VERSION >= 11000)
219	        int stages;
220	        if (use_ORDER_COL32_2R_4R4_) {
221	            stages = 15;
222	        }
223	        else {
224	            stages = 13;
225	        }
226	        cublasLtMatmulAlgoConfigSetAttribute(&algo, CUBLASLT_ALGO_CONFIG_STAGES_ID, &(stages), sizeof(stages));
227	#endif
228	    }
229	
230	    cublasLtMatmul(cublaslt_handle_,
231	                   matmulDesc,
232	                   &alphaI,
233	                   ATransform,
234	                   AtransformDesc,
235	                   kernel,
236	                   BtransformDesc,
237	                   &betaI,
238	                   res,
239	                   CtransformDesc,
240	                   res,
