392	            &algo, CUBLASLT_ALGO_CONFIG_CUSTOM_OPTION, &(customOption), sizeof(customOption));
393	        cublasLtMatmulAlgoConfigSetAttribute(&algo, CUBLASLT_ALGO_CONFIG_TILE_ID, &(tile), sizeof(tile));
394	        cublasLtMatmulAlgoConfigSetAttribute(&algo, CUBLASLT_ALGO_CONFIG_SPLITK_NUM, &(splitK_val), sizeof(splitK_val));
395	        cublasLtMatmulAlgoConfigSetAttribute(&algo, CUBLASLT_ALGO_CONFIG_CTA_SWIZZLING, &(swizzle), sizeof(swizzle));
396	        cublasLtMatmulAlgoConfigSetAttribute(
397	            &algo, CUBLASLT_ALGO_CONFIG_REDUCTION_SCHEME, &(reductionScheme), sizeof(int));
398	#if (CUDART_VERSION >= 11000)
399	        int stages;
400	        if (use_ORDER_COL32_2R_4R4_) {
401	            stages = 15;
402	        }
403	        else {
404	            stages = 13;
405	        }
406	        cublasLtMatmulAlgoConfigSetAttribute(&algo, CUBLASLT_ALGO_CONFIG_STAGES_ID, &(stages), sizeof(stages));
407	#endif
408	    }
409	
410	    float beta = 0.0f;
411	    cublasLtMatmul(cublaslt_handle_,
412	                   matmulDesc,
413	                   &alpha,
414	                   ATransform,
415	                   AtransformDesc,
416	                   kernel,
417	                   BtransformDesc,
418	                   &beta,
419	                   res,
420	                   CtransformDesc,
421	                   res,
422	                   CtransformDesc,
423	                   (findAlgo == 1 ? (&algo) : NULL),
424	                   NULL,
425	                   0,
426	                   stream_);
427	
428	    cublasLtMatmulDescDestroy(matmulDesc);
429	    cublasLtMatrixLayoutDestroy(AtransformDesc);
430	    cublasLtMatrixLayoutDestroy(BtransformDesc);
431	    cublasLtMatrixLayoutDestroy(CtransformDesc);
432	    sync_check_cuda_error();
433	    mu_->unlock();
434	}
