436	template<typename T>
437	int cublasINT8MMWrapper::getFusedINT8QKVType(const int k, const int n, const AttentionWeight<T>* attention_weights)
438	{
439	
440	    int           fusedINT8QKV_type = 0;
441	    const int8_t* Q_weight          = (const int8_t*)(attention_weights->query_weight.kernel);
442	    const int8_t* K_weight          = (const int8_t*)(attention_weights->key_weight.kernel);
443	    const int8_t* V_weight          = (const int8_t*)(attention_weights->value_weight.kernel);
444	    // for QKV weight are DataType_ & continue
445	    if ((attention_weights->query_weight.kernel + n * k == attention_weights->key_weight.kernel)
446	        && (attention_weights->key_weight.kernel + n * k == attention_weights->value_weight.kernel)) {
447	        fusedINT8QKV_type = 1;
448	    }
449	    // for QVK weight are int8 & continue
450	    else if ((Q_weight + n * k == K_weight) && (K_weight + n * k == V_weight)) {
451	        fusedINT8QKV_type = 2;
452	    }
453	    return fusedINT8QKV_type;
454	}
