468	// A is sparse weight [m,k], non transposed row major
469	// B is activation input [k, n], non transposed col major
470	void cublasINT8MMWrapper::SpGemm(
471	    const int m, const int n, const int k, const float alpha, const void* A, const void* B, void* C)
472	{
473	    cudaDataType_t                 Atype        = CUDA_R_8I;
474	    cudaDataType_t                 Btype        = CUDA_R_8I;
475	    cudaDataType_t                 Ctype        = CUDA_R_8I;
476	    cusparseComputeType            compute_type = CUSPARSE_COMPUTE_32I;
477	    cusparseOrder_t                col_order    = CUSPARSE_ORDER_COL;
478	    cusparseOrder_t                row_order    = CUSPARSE_ORDER_ROW;
479	    cusparseOperation_t            opA          = CUSPARSE_OPERATION_NON_TRANSPOSE;
480	    cusparseOperation_t            opB          = CUSPARSE_OPERATION_NON_TRANSPOSE;
481	    cusparseLtMatmulDescriptor_t   matmul;
482	    cusparseLtMatmulAlgSelection_t alg_sel;
483	    cusparseLtMatmulPlan_t         plan;
484	
485	    auto     num_A_rows = m;
486	    auto     num_A_cols = k;
487	    auto     num_B_rows = k;
488	    auto     num_B_cols = n;
489	    auto     num_C_rows = m;
490	    auto     num_C_cols = n;
491	    unsigned alignment  = 16;
492	    auto     lda        = num_A_cols;
493	    auto     ldb        = num_B_rows;
494	    auto     ldc        = num_C_rows;
495	    float    _beta(0.0f);
496	
497	    char mark[256];
498	    sprintf(mark, "%d_%d_%d_%d", 1, m, n, k);
499	    if (sp_mat_A_desc_map_.find(mark) != sp_mat_A_desc_map_.end()) {
500	        CHECK_CUSPARSE(cusparseLtMatmulDescriptorInit(&cusparselt_handle_,
501	                                                      &matmul,
502	                                                      opA,
503	                                                      opB,
504	                                                      &sp_mat_A_desc_map_[mark],
505	                                                      &sp_mat_B_desc_map_[mark],
506	                                                      &sp_mat_C_desc_map_[mark],
507	                                                      &sp_mat_C_desc_map_[mark],
508	                                                      compute_type))
509	    }
510	    else {
511	        // initializing MatDesc takes a lot of time
512	        cusparseLtMatDescriptor_t matA, matB, matC;
513	        sp_mat_A_desc_map_[mark] = matA;
514	        sp_mat_B_desc_map_[mark] = matB;
515	        sp_mat_C_desc_map_[mark] = matC;
516	        CHECK_CUSPARSE(cusparseLtStructuredDescriptorInit(&cusparselt_handle_,
517	                                                          &sp_mat_A_desc_map_[mark],
518	                                                          num_A_rows,
519	                                                          num_A_cols,
520	                                                          lda,
521	                                                          alignment,
522	                                                          Atype,
523	                                                          row_order,
524	                                                          CUSPARSELT_SPARSITY_50_PERCENT))
525	        CHECK_CUSPARSE(cusparseLtDenseDescriptorInit(
526	            &cusparselt_handle_, &sp_mat_B_desc_map_[mark], num_B_rows, num_B_cols, ldb, alignment, Btype, col_order))
527	        CHECK_CUSPARSE(cusparseLtDenseDescriptorInit(
528	            &cusparselt_handle_, &sp_mat_C_desc_map_[mark], num_C_rows, num_C_cols, ldc, alignment, Ctype, col_order))
529	        CHECK_CUSPARSE(cusparseLtMatmulDescriptorInit(&cusparselt_handle_,
530	                                                      &matmul,
531	                                                      opA,
532	                                                      opB,
533	                                                      &sp_mat_A_desc_map_[mark],
534	                                                      &sp_mat_B_desc_map_[mark],
535	                                                      &sp_mat_C_desc_map_[mark],
536	                                                      &sp_mat_C_desc_map_[mark],
537	                                                      compute_type))
538	    }
539	    mu_->lock();
540	    CHECK_CUSPARSE(
541	        cusparseLtMatmulAlgSelectionInit(&cusparselt_handle_, &alg_sel, &matmul, CUSPARSELT_MATMUL_ALG_DEFAULT))
542	    int alg = cublas_algo_map_->getSpAlgo(1, num_A_rows, num_B_cols, num_A_cols);
543	    CHECK_CUSPARSE(cusparseLtMatmulAlgSetAttribute(
544	        &cusparselt_handle_, &alg_sel, CUSPARSELT_MATMUL_ALG_CONFIG_ID, &alg, sizeof(alg)))
545	    size_t workspace_size;
546	    CHECK_CUSPARSE(cusparseLtMatmulGetWorkspace(&cusparselt_handle_, &alg_sel, &workspace_size))
547	    CHECK_CUSPARSE(cusparseLtMatmulPlanInit(&cusparselt_handle_, &plan, &matmul, &alg_sel, workspace_size))
548	
549	    void*        d_workspace = nullptr;
550	    int          num_streams = 1;
551	    cudaStream_t streams[1]  = {stream_};
552	    CHECK_CUSPARSE(
553	        cusparseLtMatmul(&cusparselt_handle_, &plan, &alpha, A, B, &_beta, C, C, d_workspace, streams, num_streams))
554	    CHECK_CUSPARSE(cusparseLtMatmulPlanDestroy(&plan))
555	    sync_check_cuda_error();
556	    mu_->unlock();
557	}
558	#endif
559	}  // namespace fastertransformer
